#!/usr/bin/env python3
"""Analyze PIP check-in process compliance from workspace source documents.

Run from workspace root with no arguments. Prints JSON to stdout and exits 0.
"""

from __future__ import annotations

import json
import math
import re
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]
CALENDAR_FILE = ROOT / "calendar-1on1-history.md"
PIP_EMAIL_FILE = ROOT / "pip-email-chain.md"
POLICY_FILE = ROOT / "labor-law-reference.md"


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def parse_policy_minimum_days(policy_text: str) -> int:
    match = re.search(r"最低改进期限\s*\|\s*\*\*(\d+)天\*\*", policy_text)
    if not match:
        match = re.search(r"PIP最低(\d+)天", policy_text)
    if not match:
        raise ValueError("Could not parse policy minimum PIP days")
    return int(match.group(1))


def parse_checkin_interval_days(policy_text: str) -> int:
    if "每两周一次" not in policy_text:
        raise ValueError("Could not parse PIP check-in interval")
    return 14


def required_formal_checkins(policy_text: str) -> int:
    minimum_days = parse_policy_minimum_days(policy_text)
    interval_days = parse_checkin_interval_days(policy_text)
    return math.floor(minimum_days / interval_days)


def actual_pip_meetings(calendar_text: str) -> list[str]:
    dates = []
    for line in calendar_text.splitlines():
        if "PIP Review" in line:
            match = re.search(r"(\d{4}-\d{2}-\d{2})", line)
            if match:
                dates.append(match.group(1))
    return dates


def written_followup_dates(email_text: str) -> list[str]:
    dates = []
    # Count actual check-in follow-up emails, not the PIP initiation email.
    for section in re.split(r"\n## 邮件 ", email_text):
        if "Check-in" in section or "检查" in section:
            if "PIP Week 2 Check-in" in section or "Week 4 Check-in" in section:
                match = re.search(r"\*\*日期:\*\*\s*(\d{4}-\d{2}-\d{2})", section)
                if match:
                    dates.append(match.group(1))
    return sorted(set(dates))


def employee_written_confirmations(email_text: str) -> int:
    confirmations = 0
    # In this source set, the explicit system note says no reply and signature blank.
    if "未回复本邮件" in email_text or "员工签名栏为空" in email_text:
        return 0
    confirmation_markers = ["确认收到", "同意上述改进计划", "员工签名"]
    if all(marker in email_text for marker in confirmation_markers):
        confirmations += 1
    return confirmations


def process_gaps(policy_text: str, calendar_text: str, email_text: str) -> list[str]:
    required = required_formal_checkins(policy_text)
    actual_dates = actual_pip_meetings(calendar_text)
    email_dates = written_followup_dates(email_text)
    gaps = []

    if len(actual_dates) < required:
        gaps.append(f"正式PIP check-in次数不足：政策按60天、每两周一次至少需要{required}次，日历仅记录{len(actual_dates)}次PIP Review。")
    if "无Week 4 Check-in邮件" in email_text:
        gaps.append("Week 4 check-in缺失：邮件链明确无Week 4 Check-in邮件。")
    if len(email_dates) < len(actual_dates):
        gaps.append(f"PIP Review并非全部有邮件跟进：日历记录{len(actual_dates)}次，邮件记录仅{len(email_dates)}次。")
    if "未回复本邮件" in email_text or "员工签名栏为空" in email_text:
        gaps.append("PIP文件缺员工书面确认：PIP启动邮件未收到员工回复，PIP协议员工签名栏为空。")
    if "下一封相关邮件为2026-03-13的解雇通知" in email_text:
        gaps.append("最终评估文档缺失：Week 2后下一封相关邮件为2026-03-13解雇通知。")
    return gaps


def build_result() -> dict:
    calendar_text = read_text(CALENDAR_FILE)
    email_text = read_text(PIP_EMAIL_FILE)
    policy_text = read_text(POLICY_FILE)

    actual_dates = actual_pip_meetings(calendar_text)
    email_dates = written_followup_dates(email_text)

    return {
        "required_formal_checkins": required_formal_checkins(policy_text),
        "actual_pip_checkins": len(actual_dates),
        "checkins_with_written_or_email_followup": len(email_dates),
        "checkins_with_employee_written_confirmation": employee_written_confirmations(email_text),
        "process_gaps": process_gaps(policy_text, calendar_text, email_text),
        "source_files": {
            "calendar": CALENDAR_FILE.name,
            "pip_email_chain": PIP_EMAIL_FILE.name,
            "policy": POLICY_FILE.name,
        },
    }


def main() -> None:
    print(json.dumps(build_result(), ensure_ascii=False, indent=2))


if __name__ == "__main__":
    main()

